//! Repository for SalesOrderItem entities
//!
//! Originally generated by metaphor-schema; now **user-owned** — this exact path is declared under
//! `user_owned` in `metaphor.codegen.yaml`, so the generator skips it wholesale. The custom methods
//! below are the home for every hand-written SalesOrderItem SQL statement — including the two
//! fulfillment watermarks (`billed_qty` / `delivered_qty`) and the `FOR UPDATE`-serialized billing
//! allocation (4-layer rule: services orchestrate and own the unit of work, repositories hold the SQL).
//!
//! Thin newtype over `backbone_orm::GenericCrudRepository<SalesOrderItem, backbone_orm::SoftDelete>`.
//! All standard CRUD methods are available via `Deref`.

use anyhow::Result;
use rust_decimal::Decimal;
use sqlx::{PgPool, Row};
use uuid::Uuid;

use backbone_orm::company_scope;

use crate::domain::entity::SalesOrderItem;

/// Table name for SalesOrderItem entities
pub const TABLE_NAME: &str = "selling.sales_order_items";

/// Repository for SalesOrderItem entities.
///
/// All standard CRUD, soft-delete, pagination, and bulk methods are
/// provided automatically via `Deref` to `backbone_orm::GenericCrudRepository`.
pub struct SalesOrderItemRepository(
    backbone_orm::GenericCrudRepository<SalesOrderItem, backbone_orm::SoftDelete>,
);

impl std::ops::Deref for SalesOrderItemRepository {
    type Target = backbone_orm::GenericCrudRepository<SalesOrderItem, backbone_orm::SoftDelete>;
    fn deref(&self) -> &Self::Target { &self.0 }
}

impl SalesOrderItemRepository {
    /// Create a new repository instance.
    pub fn new(pool: PgPool) -> Self {
        Self(backbone_orm::GenericCrudRepository::new(pool, TABLE_NAME))
    }
}

/// The exact row a sales-order-line insert writes.
///
/// Mirrors the raw column shape rather than the `SalesOrderItem` entity: `line_amount` is already
/// server-computed by the write service's `price_document`, and the `billed_qty`/`delivered_qty`
/// watermarks are deliberately absent — a new line starts at the column defaults and only the
/// watermark methods below ever move them.
pub struct NewSalesOrderItemRow<'a> {
    pub id: Uuid,
    pub order_id: Uuid,
    pub item_id: Uuid,
    pub description: Option<&'a str>,
    pub quantity: Decimal,
    pub unit_price: Decimal,
    pub line_discount: Decimal,
    pub line_amount: Decimal,
}

/// One order line as `create_invoice_from_order` copies it. Carries `id` — the invoice line links
/// back to it via `sales_order_item_id`, which is what lets posting advance `billed_qty`.
pub struct OrderLineForInvoiceRow {
    pub id: Uuid,
    pub item_id: Uuid,
    pub description: Option<String>,
    pub quantity: Decimal,
    pub unit_price: Decimal,
    pub line_discount: Decimal,
}

/// The order-wide watermark rollup behind `recompute_order_status`. Both are `Option` because
/// `bool_and` over zero rows is NULL (an order with no live lines).
pub struct WatermarkRollupRow {
    pub billed_all: Option<bool>,
    pub delivered_all: Option<bool>,
}

/// One line's undelivered remainder for the delivery envelope.
pub struct OrderDeliveryRemainderRow {
    pub item_id: Uuid,
    pub remaining: Decimal,
}

/// One line's un-invoiced remainder (plus its price) for the invoice envelope.
pub struct OrderBillingRemainderRow {
    pub item_id: Uuid,
    pub remaining: Decimal,
    pub unit_price: Decimal,
}

/// One order line's remaining billing capacity (`quantity - billed_qty`), read under `FOR UPDATE`.
pub struct LineBillingCapacityRow {
    pub id: Uuid,
    pub capacity: Decimal,
}

/// Hand-written SalesOrderItem SQL. Lives here (not in the write service) per the module's 4-layer
/// rule: services orchestrate and own the unit of work, repositories hold the SQL.
impl SalesOrderItemRepository {
    /// Insert one sales-order line.
    ///
    /// Takes the CALLER'S connection so the line commits in the SAME transaction as its header. The
    /// caller binds the company on that connection (`bind_company_on`) before calling — don't re-bind.
    pub async fn insert_line(
        &self,
        conn: &mut sqlx::PgConnection,
        l: &NewSalesOrderItemRow<'_>,
    ) -> Result<(), sqlx::Error> {
        sqlx::query(
            r#"INSERT INTO selling.sales_order_items
                (id, order_id, item_id, description, quantity, unit_price, line_discount, line_amount)
               VALUES ($1,$2,$3,$4,$5,$6,$7,$8)"#,
        )
        .bind(l.id).bind(l.order_id).bind(l.item_id).bind(l.description)
        .bind(l.quantity).bind(l.unit_price).bind(l.line_discount).bind(l.line_amount)
        .execute(conn)
        .await?;
        Ok(())
    }

    /// Read an order's lines for `create_invoice_from_order`.
    ///
    /// ID-only: no company argument, so this read rides the REQUEST-dedicated connection carrying the
    /// caller's `app.company_id` — RLS fences it (ADR-0008).
    pub async fn list_for_invoice(
        &self,
        pool: &PgPool,
        order_id: Uuid,
    ) -> Result<Vec<OrderLineForInvoiceRow>, sqlx::Error> {
        let rows = company_scope::fetch_all_rows_scoped(
            pool,
            sqlx::query(
                r#"SELECT id, item_id, description, quantity, unit_price, line_discount
                   FROM selling.sales_order_items WHERE order_id=$1 AND (metadata->>'deleted_at') IS NULL"#,
            )
            .bind(order_id),
        ).await?;
        Ok(rows.iter().map(|r| OrderLineForInvoiceRow {
            id: r.get("id"),
            item_id: r.get("item_id"),
            description: r.get("description"),
            quantity: r.get("quantity"),
            unit_price: r.get("unit_price"),
            line_discount: r.get("line_discount"),
        }).collect())
    }

    /// Roll an order's two watermarks up to a pair of order-wide booleans (ADR-003). ID-only —
    /// inherits the caller's scope (`recompute_order_status`).
    pub async fn watermark_rollup(
        &self,
        pool: &PgPool,
        order_id: Uuid,
    ) -> Result<WatermarkRollupRow, sqlx::Error> {
        let row = company_scope::fetch_one_row_scoped(
            pool,
            sqlx::query(
                r#"SELECT bool_and(billed_qty >= quantity) AS billed_all,
                          bool_and(delivered_qty >= quantity) AS delivered_all
                   FROM selling.sales_order_items
                   WHERE order_id=$1 AND (metadata->>'deleted_at') IS NULL"#,
            )
            .bind(order_id),
        ).await?;
        Ok(WatermarkRollupRow {
            billed_all: row.get("billed_all"),
            delivered_all: row.get("delivered_all"),
        })
    }

    /// Read each line's undelivered remainder (`quantity - delivered_qty > 0`) for the delivery
    /// envelope. ID-only — see [`Self::list_for_invoice`].
    pub async fn list_delivery_remainders(
        &self,
        pool: &PgPool,
        order_id: Uuid,
    ) -> Result<Vec<OrderDeliveryRemainderRow>, sqlx::Error> {
        let rows = company_scope::fetch_all_rows_scoped(
            pool,
            sqlx::query(
                r#"SELECT item_id, (quantity - delivered_qty) AS remaining
                   FROM selling.sales_order_items
                   WHERE order_id=$1 AND (metadata->>'deleted_at') IS NULL AND (quantity - delivered_qty) > 0"#,
            )
            .bind(order_id),
        ).await?;
        Ok(rows.iter().map(|r| OrderDeliveryRemainderRow {
            item_id: r.get("item_id"),
            remaining: r.get("remaining"),
        }).collect())
    }

    /// Read each line's un-invoiced remainder (`quantity - billed_qty > 0`) plus its price for the
    /// invoice envelope. ID-only — see [`Self::list_for_invoice`].
    pub async fn list_billing_remainders(
        &self,
        pool: &PgPool,
        order_id: Uuid,
    ) -> Result<Vec<OrderBillingRemainderRow>, sqlx::Error> {
        let rows = company_scope::fetch_all_rows_scoped(
            pool,
            sqlx::query(
                r#"SELECT item_id, (quantity - billed_qty) AS remaining, unit_price
                   FROM selling.sales_order_items
                   WHERE order_id=$1 AND (metadata->>'deleted_at') IS NULL AND (quantity - billed_qty) > 0"#,
            )
            .bind(order_id),
        ).await?;
        Ok(rows.iter().map(|r| OrderBillingRemainderRow {
            item_id: r.get("item_id"),
            remaining: r.get("remaining"),
            unit_price: r.get("unit_price"),
        }).collect())
    }

    /// Advance the `delivered_qty` watermark for every line of an order matching `item_id`.
    ///
    /// ID-only: no company is available — the caller (`mark_delivered`) is the inbound handler for
    /// inventory's `StockDelivered`, so the CALLER must wrap this in
    /// `with_company_scope(Some(event.company_id))`, otherwise these writes fail closed.
    pub async fn add_delivered_qty(
        &self,
        pool: &PgPool,
        order_id: Uuid,
        item_id: Uuid,
        qty: Decimal,
    ) -> Result<(), sqlx::Error> {
        company_scope::execute_scoped(
            pool,
            sqlx::query(
                r#"UPDATE selling.sales_order_items
                   SET delivered_qty = delivered_qty + $3
                   WHERE order_id=$1 AND item_id=$2 AND (metadata->>'deleted_at') IS NULL"#,
            )
            .bind(order_id).bind(item_id).bind(qty),
        ).await?;
        Ok(())
    }

    /// Advance `billed_qty` on every order line an invoice's lines point at, in one statement.
    ///
    /// Scoped through the INVOICE, not the order: the `sales_invoice_items` subquery is what the
    /// `invoice_id=$1` filter bites on, and the order lines are reached by join. ID-only — this
    /// inherits its caller's scope (`post_sales_invoice`, via `advance_billing_watermarks`).
    pub async fn advance_billed_from_invoice(
        &self,
        pool: &PgPool,
        invoice_id: Uuid,
    ) -> Result<(), sqlx::Error> {
        company_scope::execute_scoped(
            pool,
            sqlx::query(
                r#"UPDATE selling.sales_order_items soi
                   SET billed_qty = soi.billed_qty + ii.qty
                   FROM (SELECT sales_order_item_id AS soi_id, SUM(quantity) AS qty
                         FROM selling.sales_invoice_items
                         WHERE invoice_id=$1 AND sales_order_item_id IS NOT NULL
                           AND (metadata->>'deleted_at') IS NULL
                         GROUP BY sales_order_item_id) ii
                   WHERE soi.id = ii.soi_id"#,
            )
            .bind(invoice_id),
        ).await?;
        Ok(())
    }

    /// Lock an item's order lines and read their remaining billing capacity (`quantity - billed_qty`),
    /// in a stable `ORDER BY id` fill order.
    ///
    /// Takes the CALLER'S connection: the `FOR UPDATE` is only meaningful inside the caller's
    /// transaction — it is what serializes concurrent billers and closes the over-bill race. The caller
    /// binds the company on that connection (`bind_current_company`) before calling — don't re-bind.
    pub async fn lock_billing_capacity(
        &self,
        conn: &mut sqlx::PgConnection,
        order_id: Uuid,
        item_id: Uuid,
    ) -> Result<Vec<LineBillingCapacityRow>, sqlx::Error> {
        let rows = sqlx::query(
            r#"SELECT id, (quantity - billed_qty) AS capacity FROM selling.sales_order_items
               WHERE order_id=$1 AND item_id=$2 AND (metadata->>'deleted_at') IS NULL ORDER BY id FOR UPDATE"#,
        )
        .bind(order_id).bind(item_id)
        .fetch_all(conn)
        .await?;
        Ok(rows.iter().map(|r| LineBillingCapacityRow {
            id: r.get("id"),
            capacity: r.get("capacity"),
        }).collect())
    }

    /// Add to one order line's `billed_qty`. Takes the CALLER'S connection so it lands in the same
    /// transaction that holds the `FOR UPDATE` lock from [`Self::lock_billing_capacity`] — the read and
    /// the write must not be split, or the capacity check would race.
    pub async fn add_billed_qty(
        &self,
        conn: &mut sqlx::PgConnection,
        line_id: Uuid,
        qty: Decimal,
    ) -> Result<(), sqlx::Error> {
        sqlx::query("UPDATE selling.sales_order_items SET billed_qty = billed_qty + $2 WHERE id=$1")
            .bind(line_id).bind(qty)
            .execute(conn)
            .await?;
        Ok(())
    }
}

backbone_core::impl_crud_repository!(SalesOrderItemRepository, SalesOrderItem, soft_delete);
